#!/usr/bin/env node
// One-time migration script for top-level pages
// Replaces inline header/footer/scripts with build markers

const fs = require('fs');
const path = require('path');

const ROOT = '/Users/kristinesocall/Library/CloudStorage/ProtonDrive-gifteddreamers@proton.me-folder/2025-12-18 CC/kristinesocall/justNICE.us';

const pages = [
  { file: 'index.html', nav: 'home', footer: 'full' },
  { file: 'blog.html', nav: 'blog', footer: 'full' },
  { file: 'downloads.html', nav: 'downloads', footer: 'slim' },
  { file: 'immigrant-resources.html', nav: 'resources', footer: 'full' },
  { file: 'kyr-ice-training.html', nav: 'kyr', footer: 'full' },
];

function migrateFile(filePath, config) {
  let html = fs.readFileSync(filePath, 'utf8');
  const original = html;

  // 1. Insert build:config after <body ...>
  const bodyMatch = html.match(/<body[^>]*>/);
  if (!bodyMatch) {
    console.error(`  ERROR: No <body> tag found in ${path.basename(filePath)}`);
    return false;
  }
  const bodyTag = bodyMatch[0];
  const configComment = `<!-- build:config {"nav": "${config.nav}", "footer": "${config.footer}"} -->`;

  // Check if already migrated
  if (html.includes('build:config')) {
    console.log(`  SKIP: ${path.basename(filePath)} already has build:config`);
    return true;
  }

  html = html.replace(bodyTag, bodyTag + '\n' + configComment + '\n');

  // 2. Replace <header>...</header> + mobile menu div with <!-- build:nav -->
  // The header block starts with <header and ends with </header>
  // It may be preceded by comments
  const headerRegex = /\s*(?:<!--[\s\S]*?-->\s*)*<header[\s\S]*?<\/header>/;
  const headerMatch = html.match(headerRegex);
  if (headerMatch) {
    html = html.replace(headerMatch[0], '\n<!-- build:nav -->\n');
  } else {
    console.error(`  WARNING: No <header> block found in ${path.basename(filePath)}`);
  }

  // 3. Replace <footer>...</footer> with <!-- build:footer -->
  const footerRegex = /\s*(?:<!--[\s\S]*?FOOTER[\s\S]*?-->\s*)*<footer[\s\S]*?<\/footer>/;
  const footerMatch = html.match(footerRegex);
  if (footerMatch) {
    html = html.replace(footerMatch[0], '\n<!-- build:footer -->');
  } else {
    console.error(`  WARNING: No <footer> block found in ${path.basename(filePath)}`);
  }

  // 4. Replace trailing scripts (mobile menu, contact form, translations) with <!-- build:scripts -->
  // These come after the footer and before </body>
  // Pattern: one or more <script> blocks at the end, before </body>
