  { file: 'downloads.html', nav: 'downloads', footer: 'slim' },
  { file: 'immigrant-resources.html', nav: 'resources', footer: 'full' },
  { file: 'kyr-ice-training.html', nav: 'kyr', footer: 'full' },
];

// Find the outermost <tag>...</tag> block by counting nesting
function findTagBlock(html, tagName, startFrom) {
  const openTag = '<' + tagName;
  const closeTag = '</' + tagName + '>';

  let searchStart = startFrom || 0;
  let openIdx = html.indexOf(openTag, searchStart);
  if (openIdx === -1) return null;

  // Walk backwards to find preceding comments/whitespace on same block
  let blockStart = openIdx;
  // Look back for HTML comments that are part of this block
  const before = html.substring(Math.max(0, openIdx - 500), openIdx);
  const commentMatch = before.match(/(?:\s*<!--[^]*?-->\s*)+$/);
  if (commentMatch) {
    blockStart = openIdx - commentMatch[0].length;
  }

  // Find matching close tag (handle nesting)
  let depth = 0;
  let pos = openIdx;
  while (pos < html.length) {
    const nextOpen = html.indexOf(openTag, pos + 1);
    const nextClose = html.indexOf(closeTag, pos + 1);

    if (nextClose === -1) return null; // malformed

    if (nextOpen !== -1 && nextOpen < nextClose) {
      // Found a nested open tag before the close
      depth++;
      pos = nextOpen;
    } else {
      if (depth === 0) {
        // This is our matching close tag
        const blockEnd = nextClose + closeTag.length;
        return {
          start: blockStart,
          end: blockEnd,
          content: html.substring(blockStart, blockEnd)
        };
      }
      depth--;
      pos = nextClose;
    }
  }
  return null;
}

function migrateFile(filePath, config) {
  let html = fs.readFileSync(filePath, 'utf8');
  const originalLen = html.length;

  // Check if already migrated
  if (html.includes('build:config')) {
    console.log(`  SKIP: ${path.basename(filePath)} already has build:config`);
    return true;
  }

  // 1. Insert build:config after <body ...>
  const bodyMatch = html.match(/<body[^>]*>/);
  if (!bodyMatch) {
    console.error(`  ERROR: No <body> tag found`);
    return false;
  }
  const bodyIdx = html.indexOf(bodyMatch[0]);
  const afterBody = bodyIdx + bodyMatch[0].length;
  const configComment = `\n<!-- build:config {"nav": "${config.nav}", "footer": "${config.footer}"} -->`;
  html = html.substring(0, afterBody) + configComment + html.substring(afterBody);

  // 2. Find and replace <header>...</header> with <!-- build:nav -->
  const headerBlock = findTagBlock(html, 'header');
  if (headerBlock) {
    html = html.substring(0, headerBlock.start) + '\n<!-- build:nav -->\n' + html.substring(headerBlock.end);
    console.log(`    Removed header: ${headerBlock.content.length} chars`);
  } else {
    console.error(`  WARNING: No <header> block found`);
  }

  // 3. Find and replace <footer>...</footer> with <!-- build:footer -->
  const footerBlock = findTagBlock(html, 'footer');
  if (footerBlock) {
    html = html.substring(0, footerBlock.start) + '\n<!-- build:footer -->\n' + html.substring(footerBlock.end);
    console.log(`    Removed footer: ${footerBlock.content.length} chars`);
  } else {
    console.error(`  WARNING: No <footer> block found`);
  }

  // 4. Remove shared scripts and add build:scripts marker
  // Remove mobile menu toggle scripts (various patterns)
  html = html.replace(/\s*<!--\s*Mobile Menu Toggle\s*-->\s*<script>[\s\S]*?<\/script>/g, '');
  html = html.replace(/\s*<!--\s*Anonymous Contact Form Submission\s*-->\s*<script>[\s\S]*?<\/script>/g, '');

  // Remove standalone menu toggle scripts (match by variable name at start)
  // Be very specific to avoid eating page-specific scripts
  html = html.replace(/\s*<script>\s*(?:const|var)\s+menuBtn\s*=\s*document\.getElementById\('mobile-menu-btn'\)[\s\S]*?<\/script>/g, '');
  html = html.replace(/\s*<script>\s*function\s+submitContactForm\s*\(event\)[\s\S]*?<\/script>/g, '');

  // Remove translations.js and init
  html = html.replace(/\s*<script src="\/translations\.js"><\/script>/g, '');
  html = html.replace(/\s*<script>\s*if\s*\(\s*typeof\s+initTranslation\b[^<]*<\/script>/g, '');
  html = html.replace(/\s*<script>\s*document\.addEventListener\(\s*'DOMContentLoaded'\s*,\s*initTranslation\s*\)\s*;?\s*<\/script>/g, '');

  // Insert <!-- build:scripts --> before </body>
  html = html.replace(/([\s\S]*)\s*<\/body>/, '$1\n<!-- build:scripts -->\n</body>');

  // Clean up excessive blank lines
  html = html.replace(/\n{4,}/g, '\n\n');

  fs.writeFileSync(filePath, html);
  console.log(`  OK: ${path.basename(filePath)} migrated (${originalLen} -> ${html.length} bytes)`);
  return true;
}

console.log('Migrating top-level pages...');
for (const page of pages) {
  const filePath = path.join(ROOT, page.file);
  migrateFile(filePath, page);
}
console.log('Done.');

