// Eat single-line HTML comments immediately before a position (walking backwards line by line)
function eatPrecedingComments(html, pos) {
  let start = pos;
  while (start > 0) {
    // Look at the line before start
    const lineEnd = start;
    let lineStart = html.lastIndexOf('\n', start - 1);
    if (lineStart === -1) lineStart = 0;
    else lineStart += 1;
    const line = html.substring(lineStart, lineEnd).trim();
