  const trailingComments = before.match(/(\s*(?:<!--[\s\S]*?-->\s*)*)\s*$/);
  if (trailingComments && trailingComments[0].includes('<!--')) {
    // Only eat if comments exist (don't eat random whitespace)
    hStart = hStart - trailingComments[0].length;
  }

  // Also include the mobile-menu div that follows </header> (if it's inside header, it's already included)
  // Looking at the code, the mobile menu is INSIDE <header>, so headerBlock.end already covers it.

  // Step 2: Find <footer> block
  const footerBlock = findBlock(html, 'footer');
  if (!footerBlock) {
