  // Eat preceding FOOTER comment
  let fStart = footerBlock.start;
  const beforeFooter = html.substring(0, fStart);
  const footerComments = beforeFooter.match(/(\s*(?:<!--[\s\S]*?-->\s*)*)\s*$/);
  if (footerComments && footerComments[0].includes('FOOTER')) {
