  output += '</body>\n</html>\n';

  // Clean up excessive blank lines
  output = output.replace(/\n{4,}/g, '\n\n');

  fs.writeFileSync(filePath, output);
  console.log(`  OK: ${path.basename(filePath)} (${origLen} -> ${output.length} bytes)`);
