  s = s.replace(/<script>\s*(?:if\s*\(\s*typeof\s+initTranslation[^<]*|document\.addEventListener\(\s*'DOMContentLoaded'\s*,\s*initTranslation\s*\)\s*;?)\s*<\/script>/g, '');

