function findBlock(html, tagName) {
  const openTag = '<' + tagName;
  const closeTag = '</' + tagName + '>';
  let openIdx = html.indexOf(openTag, 0);
  if (openIdx === -1) return null;
  let depth = 0, pos = openIdx;
  while (pos < html.length) {
    const nextOpen = html.indexOf(openTag, pos + 1);
    const nextClose = html.indexOf(closeTag, pos + 1);
    if (nextClose === -1) return null;
    if (nextOpen !== -1 && nextOpen < nextClose) { depth++; pos = nextOpen; }
    else { if (depth === 0) return { start: openIdx, end: nextClose + closeTag.length }; depth--; pos = nextClose; }
  }
  return null;
}

