  output += pageContent + '\n\n';
  output += '<!-- build:footer -->\n';
  output += '<!-- build:scripts -->\n';
  output += '</body>\n</html>\n';
  output = output.replace(/\n{4,}/g, '\n\n');

  fs.writeFileSync(file, output);
  console.log('OK:', file, '(' + origLen + ' -> ' + output.length + ')');
}
